const data = $input.item.json;
const body = data.body || data;
const headers = data.headers || {};

const sig = headers['x-hub-signature-256'] || headers['X-Hub-Signature-256'] || headers['x-signature'] || null;

if (!body.shop_id) throw new Error('shop_id required for HMAC verification');
if (!sig) throw new Error('Missing signature header (x-hub-signature-256 or x-signature)');

const bodyStr = JSON.stringify(body);

const result = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://rvjsnkolroaakskvvwnv.supabase.co/functions/v1/verify-hmac',
  headers: {
    'Content-Type': 'application/json',
    'Authorization': 'Bearer SUPABASE_SERVICE_ROLE_KEY'
  },
  body: JSON.stringify({ shop_id: body.shop_id, signature: sig, body: bodyStr }),
  timeout: 8000,
  json: true
});

if (!result.valid) throw new Error('HMAC verification failed: ' + (result.reason || 'unknown'));

return { json: { ...body, _signature_check: 'verified' } };

const body = $input.item.json;
const errors = [];

if (!body.shop_id || !/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(body.shop_id)) errors.push('shop_id must be a valid UUID');
if (!body.sender_id || typeof body.sender_id !== 'string' || body.sender_id.length > 256) errors.push('sender_id required, max 256 chars');
if (!body.message || typeof body.message !== 'string' || body.message.length < 1 || body.message.length > 4096) errors.push('message required, 1..4096 chars');

const channel = (body.channel || 'instagram').toLowerCase();
if (!['instagram', 'whatsapp', 'telegram', 'messenger'].includes(channel)) errors.push('channel must be: instagram, whatsapp, telegram, messenger');

if (errors.length > 0) throw new Error('Validation failed: ' + errors.join('; '));

return {
  json: {
    shop_id: body.shop_id,
    sender_id: body.sender_id,
    message: body.message.trim(),
    channel: channel,
    received_at: new Date().toISOString(),
    execution_id: $execution.id
  }
};

const v = $json;

const result = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://rvjsnkolroaakskvvwnv.supabase.co/functions/v1/coin-deduct',
  headers: {
    'Content-Type': 'application/json',
    'Authorization': 'Bearer SUPABASE_SERVICE_ROLE_KEY'
  },
  body: {
    shop_id: v.shop_id,
    sender_id: v.sender_id,
    channel: v.channel
  },
  json: true,
  timeout: 5000
});

return {
  json: {
    ...v,
    _deduct_result: result,
    _coins_remaining: result.ok ? result.balance : 0
  }
};

const v = $json;
const fallback = v._deduct_result.fallback_message || 'عذراً، الرصيد غير كافٍ. يرجى شحن الرصيد من لوحة التحكم.';

// Write fallback to outbox
await this.helpers.httpRequest({
