const v = $json;
const r = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://rvjsnkolroaakskvvwnv.supabase.co/rest/v1/bot_settings?shop_id=eq.' + v.shop_id + '&select=prompt_context,target_dialect,is_active,currency,shipping_fee,delivery_cities,response_style,business_hours,fallback_message&limit=1',
  headers: { 'apikey': 'SUPABASE_SERVICE_ROLE_KEY', 'Authorization': 'Bearer SUPABASE_SERVICE_ROLE_KEY' },
  json: true,
  timeout: 5000
});
return { json: { ...v, bot_settings: r[0] || null } };

const v = $json;
let history = [];
try {
  const r = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://rvjsnkolroaakskvvwnv.supabase.co/rest/v1/conversations?select=role,message,created_at&shop_id=eq.' + v.shop_id + '&sender_id=eq.' + encodeURIComponent(v.sender_id) + '&order=created_at.desc&limit=10',
    headers: { 'apikey': 'SUPABASE_SERVICE_ROLE_KEY', 'Authorization': 'Bearer SUPABASE_SERVICE_ROLE_KEY' },
    json: true,
    timeout: 5000
  });
  history = (r || []).reverse();
} catch (e) { history = []; }
return { json: { ...v, conversation_history: history } };

const v = $json;
const settings = v.bot_settings || {};
const cfg = {
  prompt_context: settings.prompt_context || 'You are a sales assistant. Reply in Algerian Darija.',
  target_dialect: settings.target_dialect || 'Algerian Darija',
  is_active: settings.is_active !== false,
  response_style: settings.response_style || 'casual',
  currency: settings.currency || 'DZD',
  shipping_fee: settings.shipping_fee || 700,
  delivery_cities: settings.delivery_cities || [],
  business_hours: settings.business_hours || null,
  fallback_message: settings.fallback_message || null
};

if (cfg.is_active === false) throw new Error('Bot is currently disabled for this shop');

const history = Array.isArray(v.conversation_history) ? v.conversation_history : [];

// Split history: old (beyond last 3) vs recent (last 3)
const recentHistory = history.slice(-3);
const oldHistory = history.slice(0, -3);
const oldSummary = oldHistory.length > 0
  ? `[Conversation summary: ${oldHistory.length} earlier messages not shown]`
  : '(no prior conversation)';
const recentText = recentHistory.length === 0
  ? '(no recent conversation)'
  : recentHistory.map(h => (h.role === 'user' ? 'Customer' : 'You') + ': ' + h.message).join('\n');

const historyText = oldHistory.length > 0
  ? oldSummary + '\n\n[Recent messages]\n' + recentText
  : recentText || '(no prior conversation)';

const userPrompt = '[Shop context]\n' + cfg.prompt_context + '\n\n'
  + '[Conversation history]\n' + historyText + '\n\n'
  + '[Current message]\n'
  + 'Channel: ' + v.channel + '\n'
  + 'Customer says: "' + v.message + '"\n\n'
  + 'Reply in ' + cfg.target_dialect + ' using ' + cfg.response_style + ' style.\n'
  + 'Return a JSON object containing:\n'
  + '{\n'
  + '  "order_complete": boolean (true only if customer_name, phone, location_city, and product_requested are ALL present),\n'
  + '  "customer_name": string or null,\n'
  + '  "phone": string or null,\n'
  + '  "location_city": string or null,\n'
  + '  "product_requested": string or null,\n'
  + '  "quantity": integer (default 1),\n'
  + '  "reply_text": "your friendly reply in ' + cfg.target_dialect + '"\n'
  + '}\n'
  + 'If anything is missing, set order_complete=false and ask for it in reply_text. ONLY return valid JSON.';

const systemMsg = 'You are an AI sales assistant for a business. Your role:\n'
  + '- Help customers with orders politely\n'
  + '- Extract order information (name, phone, city, product, quantity)\n'
  + '- Reply in the customer\'s preferred dialect\n'
  + '- Be friendly and concise\n'
  + '- NEVER make up products or prices\n'
  + '- ALWAYS return valid JSON';

return {
  json: {
    shop_id: v.shop_id,
    sender_id: v.sender_id,
    message: v.message,
    channel: v.channel,
    received_at: v.received_at,
    execution_id: v.execution_id,
    _coins_remaining: v._coins_remaining,
    system_message: systemMsg,
    user_prompt: userPrompt,
    target_dialect: cfg.target_dialect,
    cfg: cfg
  }
};

const ctx = $json;
const groqBody = {
  model: 'llama-3.3-70b-versatile',
  messages: [
    { role: 'system', content: ctx.system_message },
    { role: 'user', content: ctx.user_prompt }
  ],
  temperature: 0.1,
  max_tokens: 1024,
  response_format: { type: 'json_object' }
};
return { json: { ...ctx, groq_body_json: JSON.stringify(groqBody) } };

const groqOut = $input.item.json;
const ctx = $('Normalize With Context').first().json;

let parsed;
try {
  const content = groqOut.choices?.[0]?.message?.content || '{}';
  parsed = typeof content === 'string' ? JSON.parse(content) : content;
} catch (e) { parsed = {}; }

const clean = (v) => (v === null || v === undefined || v === 'null' || v === '') ? null : v;
const toInt = (v) => { const n = parseInt(v, 10); return isNaN(n) ? 1 : n; };

return {
  json: {
    order_complete:    parsed.order_complete === true,
    customer_name:     clean(parsed.customer_name),
    phone:             clean(parsed.phone),
    location_city:     clean(parsed.location_city),
    product_requested: clean(parsed.product_requested),
    quantity:          toInt(parsed.quantity),
    reply_text:        parsed.reply_text || 'شكرا، راني نخدم على طلبك...',
    channel:           ctx.channel,
    sender_id:         ctx.sender_id,
    shop_id:           ctx.shop_id,
    execution_id:      ctx.execution_id,
    user_message:      ctx.message,
    _coins_remaining:  ctx._coins_remaining,
    target_dialect:    ctx.target_dialect,
    cfg:               ctx.cfg
  }
};

const v = $json;
const channel = v.channel;
let text = v.reply_text || '';

// Platform-specific formatting
if (['instagram', 'messenger'].includes(channel)) {
  // Facebook Messenger supports limited markdown:
  // *bold* _italic_ ~strikethrough~ `code`
  // Convert markdown bold/italic to FB format
  text = text
    .replace(/\*\*(.+?)\*\*/g, '*$1*')
    .replace(/__(.+?)__/g, '_$1_');
} else if (channel === 'whatsapp') {
  // WhatsApp supports: *bold* _italic_ ~strikethrough~ ```code```
  text = text
    .replace(/\*\*(.+?)\*\*/g, '*$1*')
    .replace(/__(.+?)__/g, '_$1_')
    .replace(/`{3}([\s\S]+?)`{3}/g, '```$1```');
} else if (channel === 'telegram') {
  // Telegram supports full markdown
  // Keep as-is
}

// Remove any leftover markdown that's not supported
// But keep the text clean

// Split into chunks of max 2000 characters (FB Messenger limit)
const MAX_CHUNK = 2000;
const chunks = [];
let remaining = text;

while (remaining.length > 0) {
  if (remaining.length <= MAX_CHUNK) {
    chunks.push(remaining);
    break;
  }

  // Try to split at a sentence boundary or newline
  let splitAt = remaining.lastIndexOf('. ', MAX_CHUNK);
  if (splitAt < MAX_CHUNK * 0.5) splitAt = remaining.lastIndexOf('\n', MAX_CHUNK);
  if (splitAt < MAX_CHUNK * 0.5) splitAt = remaining.lastIndexOf(' ', MAX_CHUNK);
  if (splitAt < MAX_CHUNK * 0.3) splitAt = MAX_CHUNK;

  chunks.push(remaining.substring(0, splitAt + 1).trim());
  remaining = remaining.substring(splitAt + 1).trim();
}

return {
  json: {
    ...v,
    _formatted_chunks: chunks,
    _chunk_count: chunks.length
  }
};

const v = $json;
await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://rvjsnkolroaakskvvwnv.supabase.co/rest/v1/conversations',
  headers: {
    'Content-Type': 'application/json',
    'apikey': 'SUPABASE_SERVICE_ROLE_KEY',
