return { json: v };

const v = $json;
const chunks = v._formatted_chunks || [v.reply_text || ''];

// Save each chunk as a separate conversation entry
for (let i = 0; i < chunks.length; i++) {
  await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://rvjsnkolroaakskvvwnv.supabase.co/rest/v1/conversations',
    headers: {
      'Content-Type': 'application/json',
      'apikey': 'SUPABASE_SERVICE_ROLE_KEY',
      'Authorization': 'Bearer SUPABASE_SERVICE_ROLE_KEY',
      'Prefer': 'return=minimal'
    },
    body: {
      shop_id: v.shop_id,
      sender_id: v.sender_id,
      role: 'assistant',
      message: chunks[i],
      chunk_index: i + 1,
      total_chunks: chunks.length,
      processing_status: 'completed'
    },
    json: true,
    timeout: 5000
  });
}

return { json: v };

const v = $json;

// Write seen indicator to outbox (will be processed by outbox-processor)
await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://rvjsnkolroaakskvvwnv.supabase.co/rest/v1/outbox',
