}

return { json: { ...v, _outbox_written: true, _total_chunks: chunks.length } };

const v = $json;
const qty = parseInt(v.quantity, 10) || 1;
const resp = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://rvjsnkolroaakskvvwnv.supabase.co/rest/v1/orders',
